mapper.select:
select
    id, tenant_id as "tenantId", calendar_code as "calendarCode",
    calendar_name as "calendarName", timezone,
    holiday_roll_rule as "holidayRollRule", catch_up_policy as "catchUpPolicy",
    catch_up_max_days as "catchUpMaxDays", enabled, description,
    created_at as "createdAt", updated_at as "updatedAt"
from batch.business_calendar
where tenant_id = #{tenantId}

    and calendar_code = #{calendarCode}


    and enabled = #{enabled}

order by id desc


    limit #{pageRequest.pageSize}
    offset #{offset}

select count(1)
from batch.business_calendar
where tenant_id = #{tenantId}

    and calendar_code = #{calendarCode}


    and enabled = #{enabled}

